const WebSocket = require('ws');
const http = require('http');

const server = http.createServer();
const wss = new WebSocket.Server({ server });

const players = new Map();

function isValidCommand(command) {
  const validCommands = ['build', 'attack', 'move'];
  return validCommands.includes(command.type) && Array.isArray(command.units);
}

function processCommand(player, command) {
  switch (command.type) {
    case 'build':
      // Implement build logic
      console.log(`Player ${player.id} builds ${command.units}`);
      break;
    case 'attack':
      // Implement attack logic
      console.log(`Player ${player.id} attacks with ${command.units}`);
      break;
    case 'move':
      // Implement move logic
      console.log(`Player ${player.id} moves ${command.units}`);
      break;
    default:
      console.log(`Invalid command from player ${player.id}`);
  }
}

wss.on('connection', (ws) => {
  const playerId = Math.random().toString(36).substr(2, 9);
  players.set(playerId, { id: playerId, ws });

  ws.on('message', (message) => {
    try {
      const command = JSON.parse(message);
      if (isValidCommand(command)) {
        processCommand(players.get(playerId), command);
      } else {
        console.log(`Invalid command format from player ${playerId}`);
      }
    } catch (error) {
      console.error(`Error processing message from player ${playerId}:`, error);
    }
  });

  ws.on('close', () => {
    players.delete(playerId);
    console.log(`Player ${playerId} disconnected`);
  });

  console.log(`Player ${playerId} connected`);
});

server.listen(8080, () => {
  console.log('WebSocket server is listening on ws://localhost:8080');
});